{
  "stepContent": {
    "type": "DRAG_FILL",
    "title": "Challenge: Apply Navigating the AWS Global Infrastructure",
    "lessonText": "Complete the sentences below using the available options to demonstrate your understanding of AWS Global Infrastructure concepts.",
    "data": {
      "challenges": [
        {
          "instruction": "Based on the 'Navigating the AWS Global Infrastructure' video and concept breakdown, fill in the blanks to accurately describe the relationship between AWS Regions and Availability Zones.",
          "codeTemplate": "An AWS _________ is a geographical area, while an _________ _________ is one or more discrete data centers, each with redundant power, networking, and connectivity, that are housed in separate facilities.",
          "options": [
            "Region",
            "Availability Zone",
            "Edge Location",
            "Local Zone"
          ],
          "correctAnswer": "Region,Availability Zone",
          "explanation": "A Region is a geographical area containing Availability Zones. An Availability Zone consists of one or more data centers."
        },
        {
          "instruction": "Referring to the 'Key Terms in Navigating the AWS Global Infrastructure' flashcards, complete the sentence to define the purpose of AWS Edge Locations.",
          "codeTemplate": "AWS _________ _________ are used to cache content for low latency, improving performance for end users.",
          "options": [
            "Edge Locations",
            "Regions",
            "Availability Zones",
            "Local Zones"
          ],
          "correctAnswer": "Edge Locations",
          "explanation": "Edge Locations are designed to cache content and reduce latency for users accessing AWS services globally."
        },
        {
          "instruction": "Using information from the 'Navigating the AWS Global Infrastructure' video, fill in the blanks to describe how AWS ensures high availability.",
          "codeTemplate": "AWS achieves high availability by distributing resources across multiple _________ _________ within a _________.",
          "options": [
            "Regions",
            "Availability Zones",
            "Edge Locations",
            "Local Zones"
          ],
          "correctAnswer": "Availability Zones,Region",
          "explanation": "Distributing resources across multiple Availability Zones within a Region ensures that applications remain available even if one Availability Zone fails."
        },
        {
          "instruction": "Based on the 'Concept Breakdown: Navigating the AWS Global Infrastructure', complete the sentence to explain the benefit of choosing a Region close to your users.",
          "codeTemplate": "Selecting an AWS _________ that is geographically closer to your end users reduces _________ and improves application responsiveness.",
          "options": [
            "Region",
            "Availability Zone",
            "Edge Location",
            "Latency"
          ],
          "correctAnswer": "Region,Latency",
          "explanation": "Choosing a Region closer to users minimizes the distance data must travel, thus reducing latency and improving the user experience."
        }
      ]
    }
  }
}
